const row = $input.item.json;

const get = (...keys) => {
  for (const k of keys) {
    for (const rowKey of Object.keys(row)) {
      if (rowKey.trim().toUpperCase() === k.toUpperCase()) {
        const v = row[rowKey];
        if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
      }
    }
  }
  return '';
};

const upcRaw = get('UPC');
const upcDigits = upcRaw.replace(/[^0-9]/g, '');
const upc = upcDigits.length >= 6 && upcDigits.length <= 12 ? upcDigits.padStart(12, '0') : upcDigits;
if (!upc || upc.length < 6) {
  return { json: { skip: true, upc: '', status: 'skip' } };
}

const rawBrand = get('VENDOR NAME') || 'Unbranded';
const brand = rawBrand.split('/')[0].trim() || 'Unbranded';
const productName = get('ITEM DESCRIPTION', 'PRODUCT NAME', 'DESCRIPTION');
const color = get('COLOR');
const rawSize = get('SIZE');

const SIZE_WORD_MAP = {
  'XXLARGE': 'XXL', 'XX LARGE': 'XXL', 'XXLG': 'XXL', 'XX LG': 'XXL',
  'XLARGE': 'XL', 'X LARGE': 'XL', 'XLRG': 'XL', 'X LG': 'XL',
  'LARGE': 'L', 'LRG': 'L', 'LG': 'L',
  'MEDIUM': 'M', 'MED': 'M',
  'SMALL': 'S', 'SM': 'S',
  'XSMALL': 'XS', 'X SMALL': 'XS', 'XS': 'XS',
  'XXXLARGE': '3XL', 'XXX LARGE': '3XL', '3X LARGE': '3XL', '3XLARGE': '3XL',
  'ONE SIZE': 'One Size', 'ONESIZE': 'One Size'
};

let size = '';
const rawUpper = rawSize.toUpperCase().trim();

if (SIZE_WORD_MAP[rawUpper]) {
  size = SIZE_WORD_MAP[rawUpper];
} else {
  const braMatch = rawSize.match(/(\d{2})\s*([A-Z]{1,4})/i);
  if (braMatch) {
    size = braMatch[1] + braMatch[2].toUpperCase();
  } else {
    size = rawSize.replace(/\([^)]*\)/g, '').replace(/\s+/g, '').toUpperCase().trim();
  }
}

if (!size && productName) {
  const sizeMatch = productName.match(/\b(\d{2})(AA?|[A-Z]{1,3})\b/);
  if (sizeMatch) size = sizeMatch[1] + sizeMatch[2];
}

const qty = Math.max(1, parseInt(get('ORIGINAL QTY', 'QUANTITY', 'Qty') || '1', 10) || 1);
const rawPrice = get('ORIGINAL RETAIL', 'PRICE');
const price = parseFloat(rawPrice.replace(/[$,]/g, '').trim()) || 0;
const styleNumber = get('VENDOR / STYLE #', 'VENDOR/STYLE #', 'Style #', 'MPN');
const imageUrl = get('IMAGE', 'IMAGE URL', 'Image URL', 'PHOTO').trim();
const dept = get('DEPARTMENT NAME', 'DEPARTMENT').toUpperCase().trim();

const COLOR_MAP = {
  'black':'Black','white':'White','beige':'Beige','nude':'Beige','cream':'Ivory',
  'grey':'Gray','gray':'Gray','silver':'Silver','red':'Red','darkred':'Red','wine':'Red',
  'pink':'Pink','rose':'Pink','coral':'Pink','blush':'Pink','mauve':'Pink','cerise':'Pink',
  'blue':'Blue','navy':'Blue','royal':'Blue','denim':'Blue','cobalt':'Blue',
  'green':'Green','mint':'Green','sage':'Green','olive':'Green','teal':'Green',
  'purple':'Purple','lavender':'Purple','plum':'Purple','burgundy':'Purple','violet':'Purple',
  'brown':'Brown','tan':'Brown','camel':'Brown','mocha':'Brown','chocolate':'Brown',
  'yellow':'Yellow','gold':'Gold','mustard':'Yellow','orange':'Orange',
  'ivory':'Ivory','champagne':'Ivory','natural':'Ivory','ecru':'Ivory',
  'multi':'Multicolor','multicolor':'Multicolor','print':'Multicolor','floral':'Multicolor',
  'taupe':'Taupe','heather':'Gray'
};

const EBAY_COLORS = ['Beige','Black','Blue','Brown','Gray','Green','Gold','Ivory','Multicolor','Orange','Pink','Purple','Red','Silver','White','Yellow','Taupe'];
const colorLower = color.toLowerCase().replace(/[\s\-]/g, '');
let normalizedColor = EBAY_COLORS.find(c => colorLower.includes(c.toLowerCase()));
if (!normalizedColor) {
  for (const [key, val] of Object.entries(COLOR_MAP)) {
    if (colorLower.includes(key)) { normalizedColor = val; break; }
  }
}
if (!normalizedColor) normalizedColor = color;

const hint = (productName + ' ' + dept + ' ' + brand).toLowerCase();

return { json: {
  sku: upc, upc, brand, product_name: productName,
  color_raw: color, color: normalizedColor,
  size,
  qty, price,
  style_number: styleNumber || upc,
  image_url: imageUrl,
  dept,
  category_hint: hint,
  status: 'pending', _error: null, missing_fields: []
}};

const item = $input.item.json;
if (item.status === 'review_needed') return { json: item };

const hint = (item.category_hint || '').toLowerCase();
const dept = (item.dept || '').toUpperCase().trim();
const size = item.size || '';
const braMatch = size.match(/^(\d{2})(AA?|[A-Z]{1,4})(\+?)$/);
const isBraSize = !!braMatch;

let category = 'Bras & Bra Sets';
let categoryId = '63853';

// DEPARTMENT NAME-based classification
if (['PANTIES', 'PANTY', 'PB PANTIES'].includes(dept)) {
  category = 'Panties'; categoryId = '63854';

} else if (['SHAPEWEAR', 'SHAPE WEAR'].includes(dept)) {
  category = 'Shapewear'; categoryId = '11530';

} else if (['BRAS', 'BRA', 'COLLECTIONS', 'CK INNERWEAR', 'DESGNR INNRWR'].includes(dept)) {
  category = 'Bras & Bra Sets'; categoryId = '63853';

} else if (['TRAD SLEEPWR', 'CC SLEEPWEAR', 'DRESSY SLPWR', 'NEOTRAD SLPWR', 'PB STATE/DAY', 'SLEEP', 'SLEEPWEAR'].includes(dept)) {
  category = 'Sleepwear & Robes'; categoryId = '63855';

} else if (dept === 'CLSD-KIDS ACC') {
  return { json: { ...item, status: 'review_needed', _error: 'Kids category — skip' } };

} else if (['SWIM','SWIMWEAR','SWIMSUITS','SWIMSUIT','BIKINIS','COVERUPS','COVERUP','ONE PIECES','ONE-PIECES','SWIM BOTTOMS','SWIM TOPS'].includes(dept)) {
  if (hint.includes('cover')) {
    category = 'Swimwear Cover-Ups'; categoryId = '15731';
  } else if (hint.includes('one piece') || hint.includes('onepiece')) {
    category = 'One-Piece Swimsuits'; categoryId = '15727';
  } else if (hint.includes('top') || hint.includes('bandeau')) {
    category = 'Bikini Tops'; categoryId = '16021';
  } else {
    category = 'Bikini Bottoms'; categoryId = '15734';
  }

} else if (hint.includes('bikini') || hint.includes('swim') || hint.includes('tankini')) {
  if (hint.includes('top') || hint.includes('bandeau')) {
    category = 'Bikini Tops'; categoryId = '16021';
  } else if (hint.includes('one piece') || hint.includes('onepiece')) {
    category = 'One-Piece Swimsuits'; categoryId = '15727';
  } else if (hint.includes('cover')) {
    category = 'Swimwear Cover-Ups'; categoryId = '15731';
  } else {
    category = 'Bikini Bottoms'; categoryId = '15734';
  }

} else if (hint.includes('pant') || hint.includes('thong') || hint.includes('hipster') ||
           hint.includes('cheeky') || hint.includes('boyshort') || hint.includes('bikini brief')) {
  category = 'Panties'; categoryId = '63854';

} else if (hint.includes('shape') || hint.includes('shaper') || hint.includes('cincher') ||
           hint.includes('girdle') || hint.includes('waist trainer') || hint.includes('faja')) {
  category = 'Shapewear'; categoryId = '11530';

} else if (hint.includes('sleep') || hint.includes('pajama') || hint.includes('robe') || hint.includes('nightgown')) {
  category = 'Sleepwear & Robes'; categoryId = '63855';

} else if (hint.includes('bra') || hint.includes('bralette') || hint.includes('bustier') || isBraSize) {
  category = 'Bras & Bra Sets'; categoryId = '63853';
}

let bandSize = '', cupSize = '';
if (braMatch) { bandSize = braMatch[1]; cupSize = braMatch[2]; }

let braStyle = 'T-Shirt Bra';
if (hint.includes('sports bra')) braStyle = 'Sports Bra';
else if (hint.includes('push up') || hint.includes('pushup')) braStyle = 'Push Up Bra';
else if (hint.includes('bralette')) braStyle = 'Bralette';
else if (hint.includes('balconette')) braStyle = 'Balconette Bra';
else if (hint.includes('bandeau')) braStyle = 'Bandeau Bra';
else if (hint.includes('minimizer')) braStyle = 'Minimizer Bra';
else if (hint.includes('nursing') || hint.includes('maternity')) braStyle = 'Nursing Bra';
else if (hint.includes('wireless') || hint.includes('wire free')) braStyle = 'Bralette';

let shapeStyle = 'One Piece';
if (hint.includes('high waist') || hint.includes('highwaist')) shapeStyle = 'High-Waisted';
else if (hint.includes('brief')) shapeStyle = 'Brief';
else if (hint.includes('tank') || hint.includes('cami')) shapeStyle = 'Tank';
else if (hint.includes('girdle')) shapeStyle = 'Girdle';
else if (hint.includes('waist trainer') || hint.includes('cincher')) shapeStyle = 'Waist Trainer';

const shapeSizeType = (/\d+W$/.test(size) || /^[1-9]X/.test(size) || parseInt(size) >= 18) ? 'Plus' : 'Regular';

return { json: { ...item, category, categoryId, band_size: bandSize, cup_size: cupSize, bra_style: braStyle, shape_style: shapeStyle, shape_size_type: shapeSizeType } };

const aiJson = $input.item.json;
const item = $("Classify Category").item.json;

if (item.status === "review_needed") {
  return { json: item };
}

// OpenAI content parse
let aiContent = {};
try {
  const raw = aiJson?.message?.content || '';
  aiContent = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {}

const productName = item.product_name || item.ebay_title || "";
const brand = item.brand || "Unbranded";
const color = item.color || "";
const size = item.size || "";
const categoryHint = (item.category_hint || "").toLowerCase();
const specs = item.amazon_specs || {};

const material = specs.material || "";
const closure = specs.closure || "";
const strapType = specs.strap_type || "";
const pattern = specs.pattern || "";
const careInstructions = specs.care_instructions || "";
const cupCoverage = specs.cup_coverage || "";
const braDesign = specs.bra_design || "";
const neckStyle = specs.neck_style || "";
const backStyle = specs.back_style || "";
const underwireTypeRaw = specs.underwire_type || "";
const productLine = specs.product_line || "";
const origin = specs.origin || "";
const modelNumber = specs.model_number || item.style_number || "";
const upc = item.upc || "";

const underwireType = underwireTypeRaw.toLowerCase().includes("wire")
  ? "Underwired"
  : "Wireless";

const amazonDescription = item.ebay_description || "";

const specLines = [];
if (brand) specLines.push(`<p><strong>Brand:</strong> ${brand}</p>`);
if (modelNumber) specLines.push(`<p><strong>Style Number:</strong> ${modelNumber}</p>`);
if (color) specLines.push(`<p><strong>Color:</strong> ${color}</p>`);
if (size) specLines.push(`<p><strong>Size:</strong> ${size}</p>`);
if (material) specLines.push(`<p><strong>Material:</strong> ${material}</p>`);
if (closure) specLines.push(`<p><strong>Closure:</strong> ${closure}</p>`);
if (strapType) specLines.push(`<p><strong>Strap Type:</strong> ${strapType}</p>`);
if (cupCoverage) specLines.push(`<p><strong>Features:</strong> ${cupCoverage}</p>`);
specLines.push(`<p><strong>Condition:</strong> New with Tags</p>`);
if (upc) specLines.push(`<p><strong>UPC:</strong> ${upc}</p>`);

const baseDesc = aiContent.description || amazonDescription || "";
const ebayDesc = baseDesc
  ? baseDesc
  : specLines.join("");

let ebayTitle = aiContent.title || item.ebay_title || `${brand} ${productName} ${color}`.trim();
ebayTitle = ebayTitle.replace(/shapewear/gi, "").replace(/\s+/g, " ").trim();

if (size && !ebayTitle.includes(size)) {
  ebayTitle = `${ebayTitle} ${size}`.substring(0, 80).trim();
}

if (!ebayTitle.toLowerCase().includes("nwt")) {
  ebayTitle = `${ebayTitle} NWT`.substring(0, 80).trim();
}

let specifics = {};

if (item.category === "Bras & Bra Sets") {
  const braType = productName.toLowerCase().includes("set") ? "Bra Set" : "Bra";
  const braStyle = braDesign ? `${braDesign} Bra` : (item.bra_style || "T-Shirt Bra");

  specifics = {
    Brand: [brand],
    Type: [braType],
    Style: [braStyle],
    Department: ["Women"],
    Color: [color],
    Size: [size],
    "Cup Size": [item.cup_size || ""],
    "Band Size": [item.band_size || ""],
    "Size Type": ["Regular"],
    "Underwire Type": [underwireType]
  };

  if (material) specifics["Material"] = [material];
  if (closure) specifics["Closure"] = [closure];
  if (strapType) specifics["Strap Type"] = [strapType];
  if (pattern) specifics["Pattern"] = [pattern];
  if (cupCoverage) specifics["Features"] = [cupCoverage];
  if (neckStyle) specifics["Neckline"] = [neckStyle];
  if (backStyle) specifics["Back Style"] = [backStyle];
  if (productLine) specifics["Product Line"] = [productLine];
  if (modelNumber) specifics["MPN"] = [modelNumber];
  if (origin) specifics["Country/Region of Manufacture"] = [origin];

  Object.keys(specifics).forEach((k) => {
    if (!specifics[k][0]) delete specifics[k];
  });

} else if (item.category === "Panties") {
  let pantieStyle = "Briefs";
  if (categoryHint.includes("thong") || categoryHint.includes("g-string")) pantieStyle = "Thong";
  else if (categoryHint.includes("hipster")) pantieStyle = "Hipster";
  else if (categoryHint.includes("boyshort") || categoryHint.includes("boy short")) pantieStyle = "Boy Shorts";
  else if (categoryHint.includes("cheeky")) pantieStyle = "Cheeky";

  specifics = {
    Brand: [brand],
    Style: [pantieStyle],
    Type: ["Panties"],
    Color: [color],
    Department: ["Women"],
    Size: [size]
  };

  if (material) specifics["Material"] = [material];
  if (pattern) specifics["Pattern"] = [pattern];
  if (modelNumber) specifics["MPN"] = [modelNumber];

} else if (item.category === "Shapewear") {
  specifics = {
    Brand: [brand],
    Size: [size],
    Style: [item.shape_style || "Shapewear"],
    Type: ["Shapewear"],
    Color: [color],
    Department: ["Women"],
    "Size Type": [item.shape_size_type || "Regular"]
  };

  if (material) specifics["Material"] = [material];
  if (closure) specifics["Closure"] = [closure];
  if (modelNumber) specifics["MPN"] = [modelNumber];

} else if (item.category === "Sleepwear & Robes") {
  specifics = {
    Brand: [brand],
    Size: [size],
    Color: [color],
    Department: ["Women"],
    Type: ["Nightgown"]
  };
  if (material) specifics["Material"] = [material];
  if (modelNumber) specifics["MPN"] = [modelNumber];
}

return {
  json: {
    ...item,
    product_name: productName,
    ebay_title: ebayTitle,
    ebay_description: ebayDesc,
    category_specifics: specifics
  }
};

const item = $input.item.json;
if (item.status === 'review_needed') return { json: item };

const missing = [];
const sp = item.category_specifics || {};
const cat = item.category;

if (!item.sku) missing.push('sku');
if (!item.price || item.price <= 0) missing.push('price — must be > 0');
if (!item.image_urls || item.image_urls.length === 0) missing.push('image_urls — eBay requires at least one image');
if (!item.ebay_title) missing.push('ebay_title');
if (!cat) missing.push('category');

const reqCheck = (key, label) => { if (!sp[key] || !sp[key][0]) missing.push(label || key); };

if (cat === 'Bras & Bra Sets') {
  reqCheck('Brand', 'C:Brand');
  reqCheck('Size', 'C:Size (e.g. 36DD)');
  reqCheck('Type', 'C:Type (Bra or Bra Set)');
  reqCheck('Style', 'C:Style (T-Shirt Bra etc.)');
  reqCheck('Color', 'C:Color');
  reqCheck('Department', 'C:Department');
} else if (cat === 'Panties') {
  reqCheck('Brand', 'C:Brand');
  reqCheck('Style', 'C:Style (Briefs/Thong etc.)');
  reqCheck('Type', 'C:Type');
  reqCheck('Color', 'C:Color');
  reqCheck('Department', 'C:Department');
} else if (cat === 'Shapewear') {
  reqCheck('Brand', 'C:Brand');
  reqCheck('Size', 'C:Size');
  reqCheck('Style', 'C:Style (Brief/High-Waisted etc.)');
  reqCheck('Color', 'C:Color');
  reqCheck('Department', 'C:Department');
  reqCheck('Size Type', 'C:Size Type (Regular/Plus)');
}

if (missing.length > 0) {
  return { json: { ...item, status: 'review_needed', missing_fields: missing, _error: 'Validation failed: ' + missing.join(' | ') } };
}

return { json: { ...item, status: 'approved', missing_fields: [] } };

const item = $input.item.json;
const cfg = $('Config').first().json;
const token = $('Get eBay Token').first().json.access_token;

const invPayload = {
  availability: {
    shipToLocationAvailability: { quantity: item.qty }
  },
  condition: 'NEW',
  packageWeightAndSize: {
    dimensions: {
      height: 2,
      length: 10,
      width: 5,
      unit: 'INCH'
    },
    packageType: 'PACKAGE_THICK_ENVELOPE',
    weight: {
      value: 2,
      unit: 'POUND'
    }
  },
  product: {
    aspects: item.category_specifics,
    brand: item.brand,
    description: item.ebay_description,
    imageUrls: item.image_urls && item.image_urls.length > 0 ? item.image_urls : [],
    mpn: item.style_number,
    title: item.ebay_title,
    upc: [item.upc]
  }
};

const offerPayload = {
  sku: item.sku,
  marketplaceId: 'EBAY_US',
  format: 'FIXED_PRICE',
  availableQuantity: item.qty,
  categoryId: item.categoryId,
  listingDescription: item.ebay_description,
  listingPolicies: {
    fulfillmentPolicyId: cfg.ebay_fulfillment_policy_id,
    paymentPolicyId:     cfg.ebay_payment_policy_id,
    returnPolicyId:      cfg.ebay_return_policy_id
  },
  merchantLocationKey: cfg.ebay_merchant_location_key,
  pricingSummary: {
    price: {
      currency: 'USD',
      value: String(parseFloat(item.price || 0).toFixed(2))
    }
  }
};

return { json: { ...item, _ebay_token: token, _inv_payload: invPayload, _offer_payload: offerPayload } };

// Check inventory creation result
// 204 = success (item created/updated), other = error
const resp = $input.item.json;
const prep = $('Prepare API Payloads').item.json;

const statusCode = resp.statusCode || 0;

// 204 = No Content = success for PUT inventory item
// If fullResponse, statusCode is at top level
if (statusCode === 204 || statusCode === 200) {
  return { json: { ...prep, _inv_status: 'ok', _inv_status_code: statusCode } };
}

// Check for existing offer conflict (409) — means item exists, continue anyway
if (statusCode === 409) {
  return { json: { ...prep, _inv_status: 'conflict_ok', _inv_status_code: statusCode } };
}

// Any other error — send to review
const errMsg = resp.body ? JSON.stringify(resp.body).substring(0, 200) : 'Unknown error';
return { json: { ...prep, status: 'api_error', _error: 'Create Inventory Item failed (' + statusCode + '): ' + errMsg, _inv_status: 'error' } };

const resp = $input.item.json;
const prev = $('Check Inventory Result').item.json;

const offerId = resp.offerId || null;
const errors = resp.errors || [];

if (!offerId && errors.length > 0) {
  const dupErr = errors.find(e => e.errorId === 25002 || (e.message && e.message.includes('already exists')));
  if (dupErr) {
    const existingOffer = (dupErr.parameters || []).find(p => p.name === 'offerId');
    if (existingOffer && existingOffer.value) {
      return { json: { ...prev, _offer_status: 'created', _offer_id: existingOffer.value } };
    }
    return { json: { ...prev, _offer_status: 'existing', _offer_id: null, _error: 'Offer exists but no offerId returned', status: 'already_exists' } };
  }
  return { json: { ...prev, _offer_status: 'error', _error: 'Create Offer failed: ' + JSON.stringify(errors).substring(0, 200), status: 'api_error' } };
}

return { json: { ...prev, _offer_status: 'created', _offer_id: offerId } };

const excelItems = $('Normalize Row').all();
const rainforestItems = $input.all(); // կthrowaway ենք — Amazon-ը ներսից ենք կancel անում

const RAINFOREST_KEY = '1034F764C56A4B3A85ED537C6AED2FB8';
const BARCODE_KEY = 'gteqr323t3bt52bhjbny72okpj24qi';

const results = [];

for (let index = 0; index < excelItems.length; index++) {
  const excel = excelItems[index]?.json || {};

  const rawUpc = String(excel?.upc || '').replace(/[^0-9]/g, '');
  const upc = rawUpc.length > 0 && rawUpc.length <= 12 ? rawUpc.padStart(12, '0') : rawUpc;

  let image_urls = [];
  let amazonTitle = '';
  let amazonDescription = '';
  let amazonColor = '';
  let amazonProduct = {};

  // 1. Amazon (Rainforest API)
  if (upc) {
    try {
      const rfResp = await this.helpers.request({
        method: 'GET',
        url: 'https://api.rainforestapi.com/request',
        qs: {
          api_key: RAINFOREST_KEY,
          type: 'product',
          amazon_domain: 'amazon.com',
          gtin: upc
        },
        timeout: 12000
      });
      const rfData = typeof rfResp === 'string' ? JSON.parse(rfResp) : rfResp;
      const product = rfData?.product || {};
      amazonProduct = product;

      const mainImage = String(product?.main_image?.link || '').trim();
      const rawImages = Array.isArray(product.images) ? product.images : [];
      const otherImages = rawImages
        .map(img => typeof img === 'string' ? img : String(img.link || img.url || ''))
        .filter(Boolean)
        .filter(url => url !== mainImage);
      const allImages = mainImage ? [mainImage, ...otherImages] : otherImages;
      image_urls = allImages.filter((url, i, arr) => arr.indexOf(url) === i).slice(0, 12);

      amazonTitle = String(product?.title || '').trim();
      amazonDescription = String(product?.description || '').trim();
      amazonColor = String(product?.color || '').trim();
    } catch(e) {}
  }

  // 2. Excel IMAGE column fallback
  const excelImageUrl = String(excel?.image_url || '').trim();
  if (image_urls.length === 0 && excelImageUrl) image_urls = [excelImageUrl];

  // 3. Barcodelookup fallback
  let barcodeColor = '';
  let barcodeSize = '';

  if (image_urls.length === 0 && upc) {
    try {
      const barcodeResp = await this.helpers.request({
        method: 'GET',
        url: 'https://api.barcodelookup.com/v3/products',
        qs: {
          barcode: upc,
          formatted: 'y',
          key: BARCODE_KEY
        },
        timeout: 8000
      });
      const barcodeData = typeof barcodeResp === 'string' ? JSON.parse(barcodeResp) : barcodeResp;
      const bp = barcodeData?.products?.[0] || {};

      const barcodeImages = bp.images || [];
      for (const imgUrl of barcodeImages) {
        if (imgUrl) image_urls.push(imgUrl);
      }
      image_urls = [...new Set(image_urls)].slice(0, 8);

      if (!excel?.color) barcodeColor = bp.color || '';
      if (!excel?.size) barcodeSize = bp.size || '';
    } catch(e) {}
  }

  const excelColor = String(excel?.color || '').trim();
  const finalColor = amazonColor || excelColor || barcodeColor;
  const finalSize = excel?.size || barcodeSize || '';

  const product = amazonProduct;
  const specsRaw = product?.specifications_flat ?? '';
  const specsFlat = typeof specsRaw === 'string' ? specsRaw : JSON.stringify(specsRaw);

  const getSpec = (key) => {
    if (!specsFlat) return '';
    const regex = new RegExp(key + '[:\\s]+([^.\\n]+)', 'i');
    const match = specsFlat.match(regex);
    return match ? match[1].trim() : '';
  };

  const material = product?.material || getSpec('Fabric type') || getSpec('Material Type') || '';
  const closure = getSpec('Apparel Closure Type') || getSpec('Closure type') || '';
  const strapType = getSpec('Strap Type') || '';
  const pattern = product?.pattern || getSpec('Pattern') || '';
  const careInstructions = getSpec('Care instructions') || getSpec('Product Care Instructions') || '';
  const fitType = getSpec('Fit Type') || '';
  const supportLevel = getSpec('Support Level') || '';
  const cupCoverage = getSpec('Bra Cup Coverage') || '';
  const braDesign = getSpec('Bra Design') || '';
  const neckStyle = getSpec('Neck Style') || '';
  const backStyle = getSpec('Back Style') || '';
  const underwireType = getSpec('Underwire Type') || '';
  const productLine = getSpec('Product Line') || '';
  const occasionType = getSpec('Occasion Type') || '';
  const origin = getSpec('Origin') || '';
  const modelNumber = product?.model_number || getSpec('Item model number') || '';

  const status = image_urls.length > 0 ? 'approved' : 'pending';

  results.push({
    json: {
      sku: excel?.sku || excel?.upc || '',
      upc: excel?.upc || '',
      brand: excel?.brand || '',
      color: finalColor,
      color_amazon: amazonColor,
      color_manifest: excelColor,
      size: finalSize,
      qty: excel?.qty || '',
      price: excel?.price || '',
      style_number: excel?.style_number || '',
      mpn: modelNumber || '',
      dept: excel?.dept || '',
      category_hint: excel?.category_hint || '',
      ebay_title: amazonTitle || excel?.product_name || '',
      ebay_description: amazonDescription || excel?.product_name || '',
      image_urls,
      rainforest_image_count: image_urls.length,
      status,
      amazon_specs: {
        material, closure, strap_type: strapType, pattern,
        care_instructions: careInstructions, fit_type: fitType,
        support_level: supportLevel, cup_coverage: cupCoverage,
        bra_design: braDesign, neck_style: neckStyle, back_style: backStyle,
        underwire_type: underwireType, product_line: productLine,
        occasion_type: occasionType, origin, model_number: modelNumber
      }
    }
  });
}

return results;

const excel = $('Normalize Row').item.json || {};
const rainforest = $json || {};
const product = rainforest?.product || {};

const clean = (v) => String(v || '').trim().toLowerCase();
const digits = (v) => String(v || '').replace(/\D/g, '');
const normalizeSize = (v) => String(v || '').trim().toUpperCase();

// Manifest
const manifestBrand = clean(excel.brand);
const manifestTitle = clean(excel.product_name || excel.ebay_title || '');
const manifestSize = normalizeSize(excel.size);

// Amazon
const amazonBrand = clean(product.brand);
const amazonTitle = clean(product.title);
const amazonDesc = clean(product.description);
const amazonText = `${amazonBrand} ${amazonTitle} ${amazonDesc}`.trim();

const amazonUpc =
  digits(product.upc) ||
  digits(product.gtin) ||
  digits(product.ean) ||
  digits(product.barcode) ||
  digits(product.barcodes?.[0]) ||
  '';

const manifestUpc = digits(excel.upc);

const amazonSize =
  normalizeSize(product.size) ||
  normalizeSize(product.size_name) ||
  '';

let score = 0;
const reasons = [];

// 1) UPC check (helper only, not final truth)
if (manifestUpc && amazonUpc) {
  if (manifestUpc === amazonUpc) {
    score += 15;
    reasons.push('upc_match');
  } else {
    score -= 80;
    reasons.push('upc_mismatch');
  }
} else {
  reasons.push('upc_not_available');
}

// 2) Brand check
if (manifestBrand && amazonBrand) {
  if (
    amazonBrand.includes(manifestBrand) ||
    manifestBrand.includes(amazonBrand)
  ) {
    score += 30;
    reasons.push('brand_match');
  } else {
    score -= 60;
    reasons.push('brand_mismatch');
  }
} else {
  reasons.push('brand_not_available');
}

// 3) Title similarity check
const stopWords = new Set([
  'womens','women',"women's",'mens','men',"men's",
  'the','and','with','for','all','new','tags','tag','nwt'
]);

const manifestTokens = [...new Set(
  manifestTitle
    .replace(/[^a-z0-9\s-]/g, ' ')
    .split(/\s+/)
    .map(t => t.trim())
    .filter(t => t.length >= 3 && !stopWords.has(t))
)];

let titleHits = 0;
for (const token of manifestTokens) {
  if (amazonText.includes(token)) titleHits++;
}

const titleRatio = manifestTokens.length ? titleHits / manifestTokens.length : 0;

if (titleRatio >= 0.6) {
  score += 25;
  reasons.push('title_match_strong');
} else if (titleRatio >= 0.35) {
  score += 10;
  reasons.push('title_match_partial');
} else {
  score -= 60;
  reasons.push('title_mismatch');
}

// 4) Size check
if (manifestSize) {
  if (amazonSize && manifestSize === amazonSize) {
    score += 20;
    reasons.push('size_match');
  } else if (amazonText.includes(manifestSize.toLowerCase())) {
    score += 10;
    reasons.push('size_match_text');
  } else {
    score -= 25;
    reasons.push('size_mismatch');
  }
} else {
  reasons.push('size_not_available');
}

// 5) Hard reject logic for wrong product family
const manifestLooksBra =
  /\bbra\b|\bunderwire\b|\bpush-?up\b|\bt-?shirt bra\b|\b\d{2,3}[a-z]{1,3}\b/.test(manifestTitle);

const amazonLooksMensBriefs =
  /\bmen\b|\bmens\b|\bmen's\b|\bbrief\b|\bbriefs\b|\bwaistband\b|\bx-large\b|\bmid rise\b/.test(amazonText);

if (manifestLooksBra && amazonLooksMensBriefs) {
  score = -120;
  reasons.push('hard_reject_bra_vs_mens_briefs');
}

// Final decision
let amazon_match_status = 'review_needed';

if (
  reasons.includes('upc_mismatch') ||
  reasons.includes('hard_reject_bra_vs_mens_briefs')
) {
  amazon_match_status = 'reject';
} else if (score >= 55) {
  amazon_match_status = 'approved';
} else if (score < 20) {
  amazon_match_status = 'reject';
}

return {
  json: {
    ...$json,
    amazon_match_score: score,
    amazon_match_reason: reasons.join(', '),
    amazon_match_status
  }
};

